-- ============================================================================
-- PropertyInsta – Supabase Seed Data
-- Run AFTER schema.sql in Supabase SQL Editor
-- Seeds all 60 properties, 18 reels, 20 stories, 28 builders from static data
-- ============================================================================

-- ============================================================================
-- 1. PROPERTIES (60 listings – IDs 1-60)
-- Computed fields derived from raw JS data:
--   badge        = hot → 'Hot Deal' | featured → 'Featured' | NULL
--   open_house   = featured AND NOT hot
--   parking      = amenities includes 'parking' ? type='villa' ? '2 Covered' : '1 Covered' : 'None'
--   price_per_sqft = ROUND(price / sqft)
--   facing       = pseudo-random from ['East','North','North-East','South-East'] via id % 4
--   verified     = featured
--   trending     = hot
--   age          = possession_status='Ready to Move' ? 'Ready' : 'New Launch'
--   media_aspect_ratio = '4/3'
--   listing_status    = possession_status
--   type         = capitalised first letter
--   amenities    = raw keys JSONB (mapDBProperty converts to labels at runtime)
--   neighborhood = enriched string array JSONB
--   status       = 'For Sale' (display value)
-- ============================================================================

INSERT INTO properties (id, title, location, price, beds, baths, sqft, type, status, builder, rera_id, possession_status, floor, furnishing, emi_estimate, bank_offers, images, amenities, featured, hot, badge, open_house, facing, parking, price_per_sqft, verified, views, description, agent_id, agent_name, agent_avatar, agent_rating, agent_sales, agent_phone, agent_email, post_date, comments, shares, lat, lng, neighborhood, floor_plan, trending, age, media_aspect_ratio, listing_status)
